UPDATE public.site_content SET value = 'Somos uma consultoria boutique especializada na transição de famílias e profissionais do Brasil para Portugal. Mudar de país é uma das decisões mais complexas da sua vida e a maioria chega fragmentada entre advogados, corretores, escolas e contadores, cada um no seu quadrado, ninguém coordenando o todo. A MOOVIA existe para ser a única ligação de que você precisa: antes, durante e depois da chegada.' WHERE key = 'hero.lead';